1	import { readFileSync } from "node:fs";
2	import { quote, claim } from "./claim-office.js";
3	
4	type Step = any;
5	
6	const KNOWN_ITEM_TYPES = ["sword", "amulet", "staff", "potion", "rune", "moonstone"];
7	
8	function validateItems(items: Step[]): void {
9	  for (const item of items) {
10	    if (!KNOWN_ITEM_TYPES.includes(item.type)) {
11	      throw new Error(`Unknown item type: ${item.type}`);
12	    }
13	  }
14	}
15	
16	function executeQuote(step: Step, years: number): any {
17	  validateItems(step.items);
18	  return quote({ items: step.items, years, priorContract: false });
19	}
20	
21	function validateDamagesAgainstPolicy(damages: Step[], policyItems: Step[]): void {
22	  const policyItemTypes = policyItems.map((i: any) => i.type);
23	  for (const damage of damages) {
24	    if (!policyItemTypes.includes(damage.itemType)) {
25	      throw new Error(`Damage references item not in policy: ${damage.itemType}`);
26	    }
27	  }
28	}
29	
30	function executeClaim(step: Step, steps: Step[]): any {
31	  const referencedQuote = steps[step.policy];
32	  validateDamagesAgainstPolicy(step.incident.damages, referencedQuote.items);
33	  return claim({ policy: { items: referencedQuote.items }, incident: step.incident });
34	}
35	
36	function executeStep(step: Step, steps: Step[], years: number): any {
37	  if (step.op === "claim") {
38	    return executeClaim(step, steps);
39	  }
40	  return executeQuote(step, years);
41	}
42	
43	try {
44	  const scenario = JSON.parse(readFileSync(0, "utf-8"));
45	  const years = scenario.customer.yearsWithMHPCO;
46	  const steps: Step[] = scenario.steps;
47	  const results = steps.map((step) => executeStep(step, steps, years));
48	  process.stdout.write(JSON.stringify({ results }));
49	} catch (e: any) {
50	  process.stderr.write(`Error: ${e.message}\n`);
51	  process.exit(1);
52	}
